import{_ as t,o as n,c as r,a3 as i}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"13. Individual Flexibility Arrangement","description":"","frontmatter":{"title":"13. Individual Flexibility Arrangement","eba":"Health Allied & Managers Admin 2021-2025","topics":["hours","on-call","flexible-work","preliminary"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/preliminary/13-individual-flexibility-arrangement.md","filePath":"ebas/has-managers-admin/common-terms/preliminary/13-individual-flexibility-arrangement.md"}'),a={name:"ebas/has-managers-admin/common-terms/preliminary/13-individual-flexibility-arrangement.md"};function o(s,e,l,m,p,g){return n(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="_13-individual-flexibility-arrangement" tabindex="-1">13. Individual Flexibility Arrangement <a class="header-anchor" href="#_13-individual-flexibility-arrangement" aria-label="Permalink to &quot;13. Individual Flexibility Arrangement&quot;">​</a></h1><p><strong>13.1</strong> An Employee and the Employer may, after an Employee has commenced employment, enter into an individual flexibility arrangement pursuant to this clause in order to meet the genuine needs of the Employee and Employer. An individual flexibility arrangement must be genuinely agreed to, without duress or coercion, by the Employee and Employer.</p><p><strong>13.2</strong> An individual flexibility arrangement may vary the effect of one or more of the following terms of this enterprise agreement:</p><p><strong>(a)</strong> arrangements for when work is performed;</p><p><strong>(b)</strong> breaks between successive shifts;</p><p><strong>(c)</strong> On Call, specifically to address remaining on-site overnight for the On Call period;</p><p><strong>(d)</strong> overtime rates;</p><p><strong>(e)</strong> penalty rates;</p><p><strong>(f)</strong> allowances; and</p><p><strong>(g)</strong> leave loading.</p><p><strong>13.3</strong> An Employer who wishes to initiate the making of an individual flexibility arrangement must:</p><p><strong>(a)</strong> give the Employee a written proposal; and</p><p><strong>(b)</strong> if the Employer is aware that the Employee has, or reasonably should be aware that the Employee may have, limited understanding of written English, take reasonable steps (including providing a translation in an appropriate language) to ensure that the employee understands the proposal.</p><p><strong>13.4</strong> An Employee may nominate a representative to assist in negotiations for an individual flexibility arrangement.</p><p><strong>13.5</strong> The Employer must ensure that any individual flexibility arrangement will result in the Employee being better off overall than the Employee would have been if no individual flexibility arrangement were agreed to.</p><p><strong>13.6</strong> The Employer must ensure that an individual flexibility arrangement is in writing and signed by the Employee and Employer. If the Employee is under 18 the arrangement must also be signed by a parent or guardian of the Employee.</p><p><strong>13.7</strong> The Employer must give a copy of the individual flexibility arrangement to the Employee within 14 days after it is agreed to, and keep a copy as a time and wages record.</p><p><strong>13.8</strong> The Employer must ensure that any individual flexibility arrangement sets out:</p><p><strong>(a)</strong> the terms of this enterprise agreement that will be varied by the arrangement;</p><p><strong>(b)</strong> how the arrangement will vary the effect of the terms;</p><p><strong>(c)</strong> how the Employee will be better off overall in relation to the terms and conditions of his or her employment as a result of the arrangement; and</p><p><strong>(d)</strong> the day on which the arrangement commences.</p><p><strong>13.9</strong> The Employer must ensure that any individual flexibility arrangement:</p><p><strong>(a)</strong> is about matters that would be permitted matters under section 172 of the Act if the arrangement were an enterprise agreement;</p><p><strong>(b)</strong> does not include any term that would be an unlawful term under agreement; and</p><p><strong>(c)</strong> provides for the arrangement to be terminated:</p><p><strong>(i)</strong> by either the Employee or Employer giving a specified period of written notice, with the specified period being no more than 28 days; and</p><p><strong>(ii)</strong> at any time by written agreement between the Employee and Employer.</p><p><strong>13.10</strong> An individual flexibility arrangement may be expressed to operate for a specified term or while the Employee is performing a specified role (such as acting in a specified higher position). Such an arrangement will terminate on expiry of the specified term or when the Employee ceases to perform the specified role unless terminated earlier on notice or by agreement.</p><p>Plain language terms: IFA, individual flex agreement.</p>',30)])])}const y=t(a,[["render",o]]);export{h as __pageData,y as default};
